<script>
import { createUploaderComponent } from 'quasar'
import { computed, ref } from 'vue'
import { default as FirebaseManager } from '../FirebaseManager'
// import { Service } from 'src/services/base'
// import { QUploaderBase } from 'quasar'

const storage = FirebaseManager.getInstance().getModules().storage
const storageRef = FirebaseManager.getInstance().getStorageRef()

export default createUploaderComponent({
  name: 'Uploader',
  // mixins:[QUploaderBase],

  props: {
    population: {
      type: Object,
      default: () => ({})
    },
    storageRef: {
      type: String,
      required: true
    },
    index: {
      type: Number,
      required: true
    },
    metadata: {
      type: Object,
      default: () => ({})
    },
  },
  // data()
  // {
  //   return {
  //     uploadActive: false,
  //     uploadProgress: 0
  //   }
  // },
  emits: [
    'upload-success',
    'upload-error',
    'upload-progress',
  ],

  injectPlugin({ props, emit, helpers }) {
    function generateUUID(filename) {
      const lut = [];
      for (let i = 0; i < 256; i++) {
        lut[i] = (i < 16 ? '0' : '') + (i).toString(16);
      }
      const d0 = Math.random() * 0xffffffff | 0;
      const d1 = Math.random() * 0xffffffff | 0;
      const d2 = Math.random() * 0xffffffff | 0;
      const d3 = Math.random() * 0xffffffff | 0;
      const uuid = lut[d0 & 0xff] + lut[d0 >> 8 & 0xff] + lut[d0 >> 16 & 0xff] + lut[d0 >> 24 & 0xff] + '-' +
        lut[d1 & 0xff] + lut[d1 >> 8 & 0xff] + '-' + lut[d1 >> 16 & 0x0f | 0x40] + lut[d1 >> 24 & 0xff] + '-' +
        lut[d2 & 0x3f | 0x80] + lut[d2 >> 8 & 0xff] + '-' + lut[d2 >> 16 & 0xff] + lut[d2 >> 24 & 0xff] +
        lut[d3 & 0xff] + lut[d3 >> 8 & 0xff] + lut[d3 >> 16 & 0xff] + lut[d3 >> 24 & 0xff];
      return `${uuid}.${filename.split('.')[1]}`
    }
    const uploadActive = ref(false)
    const uploadProgress = ref(0)
    const filename = ref('')

    const files = computed(() => helpers.queuedFiles.value)

    const tasks = computed(() => {
      if (files.value.length === 0 && uploadActive.value) return []

      return files.value.map(file => function () {
        filename.value = generateUUID(file.name)
        storage.ref(storageRef.fullPath).child(filename.value).put(file, { customMetadata: props.metadata })
      })

    })

    const isUploading = computed(() => {
      if (files.value.length === 0) return false
      return tasks.value.some(task => task.state === 'running')
    })

    const isBusy = computed(() => {
      if (files.value.length === 0) return false
      return tasks.value.some(task => task.state === 'paused')
    })

    function abort() {
      if (files.value.length === 0) return
      tasks.value.forEach(task => task.cancel())
    }
    async function upload() {
      if (props.population !== {} && props.population.service !== undefined && props.population.data !== null) {
        await populate2DB()
      } else {
        await uploadFile()
      }
    }


    async function uploadFile() {
      uploadActive.value = true
      console.log(props.metadata)

      files.value.forEach(async (file) => {
        filename.value = generateUUID(file.name)
        const uploadTask = storage
          .ref(storageRef.fullPath)
          .child(filename.value)
          .put(file, { customMetadata: props.metadata });

        uploadTask.on(
          'state_changed',
          function (snapshot) {
            console.log(snapshot.bytesTransferred);
            const progress = (snapshot.bytesTransferred / snapshot.totalBytes) * 100;
            uploadProgress.value = snapshot.bytesTransferred;
            // this.uploadProgress = progress;
            helpers.updateFileStatus(file, 'uploading', progress);
            emit('upload-progress', progress);
          },
          function (err) {
            helpers.updateFileStatus(file, 'failed');
            emit('upload-error', err);
          },
          function () {
            uploadTask.snapshot.ref.getDownloadURL().then(function (downloadURL) {
              emit('upload-success', props.index, downloadURL);
              helpers.updateFileStatus(file, 'uploaded');
              helpers.uploadedSize.value += file.size;
              helpers.queuedFiles.value = helpers.queuedFiles.value.filter(
                (f) => f.name !== file.name
              );
              helpers.uploadedFiles.value.push(file);
            });
          }
        );
      });

    }

    async function populate2DB() {
      const service = props.population.service
      // process population.data, which is a csv file
      uploadActive.value = true
      console.log(props.metadata)

      files.value.forEach(async (file) => {
        // file is a csv file, process it into a list of objects
        const data = await file.text()
        const lines = data.split('\n')
        const headers = lines[0].split(',')
        const rows = lines.slice(1)
        const objects = rows.map(row => {
          const values = row.split(',')
          const obj = {}
          headers.forEach((header, index) => {
            obj[header] = values[index]
          })
          return obj
        })
        var uploadedRows = 0
        for (const obj of objects) {
          await service.create(obj)
            .then((response) => {
              uploadedRows++
              const progress = (uploadedRows / objects.length) * 100;
              uploadProgress.value = uploadedRows;
              emit('upload-progress', progress);
            }).catch((error) => {
              helpers.updateFileStatus(file, 'failed');
              emit('upload-error', error);
            })
        }
        helpers.uploadedFiles.value.push(file);


      });
    }

    return {
      isUploading,
      isBusy,
      abort,
      upload,
      uploadProgress
    }
  }
})
</script>
